import Phaser from 'phaser'
import {
	GAME_WIDTH,
	GAME_HEIGHT,
	GRID,
	SCORING,
	ANIMATION,
	CANDY_COLORS,
	COLORS,
	UI,
	CANDY_SPRITE,
	GRID_PIXEL_SIZE,
	LEVELS,
	LevelConfig,
	BOMB_FRAMES,
	BOMB_SCORING,
} from '../constants'
import { CandyData, Match, GameState, GamePhase, BombType } from '../types'
import { CandyCrushAudioManager } from '../utils/audioManager'

export class MainScene extends Phaser.Scene {
	// Grid data
	private grid: (CandyData | null)[][] = []
	private gridContainer!: Phaser.GameObjects.Container

	// Level configuration
	private levelConfig!: LevelConfig
	private candyTypes!: number

	// Game state
	private gameState!: GameState
	private selectedCandy: CandyData | null = null
	private isAnimating = false
	private useProcedural = false

	// UI elements
	private scoreText!: Phaser.GameObjects.Text
	private movesText!: Phaser.GameObjects.Text
	private targetText!: Phaser.GameObjects.Text
	private progressBar!: Phaser.GameObjects.Graphics
	private chainIndicator!: Phaser.GameObjects.Text

	// Callbacks from React
	private onScoreUpdate!: (score: number) => void
	private onMovesUpdate!: (moves: number) => void
	private onGameComplete!: (won: boolean, score: number) => void
	private onPhaseChange!: (phase: GamePhase) => void

	// Selection indicator
	private selectionIndicator!: Phaser.GameObjects.Graphics

	// Audio manager
	private audio!: CandyCrushAudioManager

	// Dynamic HUD colors (derived from brandColor or fallback to defaults)
	private hudColors!: { target: number; score: number; moves: number }

	constructor() {
		super({ key: 'MainScene' })
	}

	create() {
		// Get callbacks from registry
		this.onScoreUpdate = this.registry.get('onScoreUpdate') || (() => {})
		this.onMovesUpdate = this.registry.get('onMovesUpdate') || (() => {})
		this.onGameComplete = this.registry.get('onGameComplete') || (() => {})
		this.onPhaseChange = this.registry.get('onPhaseChange') || (() => {})

		// Check if using procedural graphics
		this.useProcedural = this.registry.get('useProcedural') || false

		// Get audio manager from registry
		this.audio = this.registry.get('audioManager')

		// Derive HUD colors from brandColor or use defaults
		this.hudColors = this.deriveHudColors(this.registry.get('brandColor'))

		// Get level configuration from registry (default to level 1)
		this.levelConfig = this.registry.get('levelConfig') || LEVELS[0]
		this.candyTypes = this.levelConfig.candyTypes

		// Initialize game state with level-specific values
		this.gameState = {
			phase: 'playing',
			score: 0,
			moves: this.levelConfig.moves,
			targetScore: this.levelConfig.targetScore,
			livesRemaining: this.registry.get('lives') || 3,
			chainLevel: 0,
			lastMatchPoints: 0,
		}

		// Setup game elements
		this.createBackground()
		this.createUI()
		this.createGrid()
		this.fillGridWithCandies()
		this.removeInitialMatches()
		this.setupInput()

		// Notify React of initial state
		this.onMovesUpdate(this.gameState.moves)
		this.onScoreUpdate(this.gameState.score)
		this.onPhaseChange('playing')
	}

	// ==================== COLOR HELPERS ====================

	private deriveHudColors(brandColor?: string): {
		target: number
		score: number
		moves: number
	} {
		if (!brandColor) {
			return {
				target: COLORS.targetAccent,
				score: COLORS.scoreAccent,
				moves: COLORS.movesAccent,
			}
		}

		const hsl = this.hexToHsl(brandColor)
		// Primary: brandColor as-is
		const target = this.hslToHex(hsl.h, hsl.s, hsl.l)
		// +40° hue shift, slightly lighter
		const score = this.hslToHex(
			(hsl.h + 120) % 360,
			Math.min(hsl.s, 90),
			Math.min(hsl.l + 10, 80)
		)
		// +180° complementary hue shift
		const moves = this.hslToHex(
			(hsl.h + 240) % 360,
			Math.min(hsl.s, 85),
			Math.min(hsl.l + 5, 70)
		)

		return { target, score, moves }
	}

	private hexToHsl(hex: string): { h: number; s: number; l: number } {
		const clean = hex.replace('#', '')
		const r = parseInt(clean.substring(0, 2), 16) / 255
		const g = parseInt(clean.substring(2, 4), 16) / 255
		const b = parseInt(clean.substring(4, 6), 16) / 255

		const max = Math.max(r, g, b)
		const min = Math.min(r, g, b)
		const l = (max + min) / 2
		let h = 0
		let s = 0

		if (max !== min) {
			const d = max - min
			s = l > 0.5 ? d / (2 - max - min) : d / (max + min)
			if (max === r) h = ((g - b) / d + (g < b ? 6 : 0)) / 6
			else if (max === g) h = ((b - r) / d + 2) / 6
			else h = ((r - g) / d + 4) / 6
		}

		return { h: h * 360, s: s * 100, l: l * 100 }
	}

	private hslToHex(h: number, s: number, l: number): number {
		const sN = s / 100
		const lN = l / 100
		const c = (1 - Math.abs(2 * lN - 1)) * sN
		const x = c * (1 - Math.abs(((h / 60) % 2) - 1))
		const m = lN - c / 2

		let r = 0,
			g = 0,
			b = 0
		if (h < 60) {
			r = c
			g = x
		} else if (h < 120) {
			r = x
			g = c
		} else if (h < 180) {
			g = c
			b = x
		} else if (h < 240) {
			g = x
			b = c
		} else if (h < 300) {
			r = x
			b = c
		} else {
			r = c
			b = x
		}

		const ri = Math.round((r + m) * 255)
		const gi = Math.round((g + m) * 255)
		const bi = Math.round((b + m) * 255)

		return (ri << 16) | (gi << 8) | bi
	}

	// ==================== BACKGROUND & UI ====================

	private createBackground() {
		// Main background
		const bg = this.add.graphics()
		bg.fillStyle(COLORS.background, 1)
		bg.fillRect(0, 0, GAME_WIDTH, GAME_HEIGHT)

		// Grid background with rounded corners effect
		const gridBg = this.add.graphics()
		gridBg.fillStyle(COLORS.gridBackground, 1)
		gridBg.fillRoundedRect(
			GRID.offsetX - 10,
			GRID.offsetY - 10,
			GRID_PIXEL_SIZE + 20,
			GRID_PIXEL_SIZE + 20,
			15
		)

		// Grid border
		gridBg.lineStyle(3, COLORS.gridBorder, 1)
		gridBg.strokeRoundedRect(
			GRID.offsetX - 10,
			GRID.offsetY - 10,
			GRID_PIXEL_SIZE + 20,
			GRID_PIXEL_SIZE + 20,
			15
		)
	}

	private createUI() {
		const gameFont = '"Luckiest Guy", Arial, sans-serif'
		const textResolution = Math.min(window.devicePixelRatio || 1, 2)

		// Create header panel background
		this.createHeaderPanel()

		// Target score display
		this.targetText = this.add.text(
			UI.targetDisplay.x,
			UI.targetDisplay.y,
			'',
			{
				fontFamily: gameFont,
				fontSize: '24px',
				color: '#ffffff',
				align: 'center',
			}
		)
		this.targetText.setOrigin(0.5, 0.5)
		this.targetText.setResolution(textResolution)
		this.updateTargetDisplay()

		// Score display
		this.scoreText = this.add.text(UI.scoreDisplay.x, UI.scoreDisplay.y, '0', {
			fontFamily: gameFont,
			fontSize: '28px',
			color: '#ffd700',
			align: 'center',
		})
		this.scoreText.setOrigin(0.5, 0.5)
		this.scoreText.setResolution(textResolution)

		// Moves display
		this.movesText = this.add.text(UI.movesDisplay.x, UI.movesDisplay.y, '', {
			fontFamily: gameFont,
			fontSize: '24px',
			color: '#ffffff',
			align: 'center',
		})
		this.movesText.setOrigin(0.5, 0.5)
		this.movesText.setResolution(textResolution)
		this.updateMovesDisplay()

		// Progress bar background
		this.progressBar = this.add.graphics()
		this.updateProgressBar()

		// Chain indicator (hidden by default) - positioned below the grid
		const gridBottom = GRID.offsetY + GRID_PIXEL_SIZE
		this.chainIndicator = this.add.text(GAME_WIDTH / 2, gridBottom + 45, '', {
			fontFamily: gameFont,
			fontSize: '32px',
			color: '#ffffff',
			align: 'center',
			stroke: '#000000',
			strokeThickness: 4,
		})
		this.chainIndicator.setOrigin(0.5, 0.5)
		this.chainIndicator.setResolution(textResolution)
		this.chainIndicator.setAlpha(0)

		// Selection indicator
		this.selectionIndicator = this.add.graphics()
		this.selectionIndicator.setDepth(10)
	}

	private createHeaderPanel() {
		const panel = this.add.graphics()

		// Main header panel background with gradient effect
		panel.fillStyle(COLORS.headerPanel, 1)
		panel.fillRoundedRect(
			UI.header.x,
			UI.header.y,
			UI.header.width,
			UI.header.height,
			UI.header.borderRadius
		)

		// Subtle inner highlight at top
		panel.fillStyle(0xffffff, 0.05)
		panel.fillRoundedRect(
			UI.header.x + 2,
			UI.header.y + 2,
			UI.header.width - 4,
			20,
			{
				tl: UI.header.borderRadius - 2,
				tr: UI.header.borderRadius - 2,
				bl: 0,
				br: 0,
			}
		)

		// Header border
		panel.lineStyle(2, COLORS.headerBorder, 1)
		panel.strokeRoundedRect(
			UI.header.x,
			UI.header.y,
			UI.header.width,
			UI.header.height,
			UI.header.borderRadius
		)

		// Create stat cards
		const cardY = UI.header.y + UI.header.padding
		const cardHeight = UI.statCard.height

		// Target card (left)
		this.createStatCard(
			panel,
			UI.header.x + UI.header.padding,
			cardY,
			UI.statCard.width,
			cardHeight,
			this.hudColors.target,
			'META'
		)

		// Score card (center) - wider
		const scoreCardWidth = UI.statCard.width + 20
		this.createStatCard(
			panel,
			GAME_WIDTH / 2 - scoreCardWidth / 2,
			cardY,
			scoreCardWidth,
			cardHeight,
			this.hudColors.score,
			'PUNTOS'
		)

		// Moves card (right)
		this.createStatCard(
			panel,
			UI.header.x + UI.header.width - UI.header.padding - UI.statCard.width,
			cardY,
			UI.statCard.width,
			cardHeight,
			this.hudColors.moves,
			'TURNOS'
		)
	}

	private createStatCard(
		graphics: Phaser.GameObjects.Graphics,
		x: number,
		y: number,
		width: number,
		height: number,
		accentColor: number,
		label: string
	) {
		const gameFont = '"Luckiest Guy", Arial, sans-serif'
		const textResolution = Math.min(window.devicePixelRatio || 1, 2)
		const accentHeight = UI.statCard.accentHeight

		// Card background
		graphics.fillStyle(COLORS.statCardBg, 0.8)
		graphics.fillRoundedRect(x, y, width, height, UI.statCard.borderRadius)

		// Accent bar at top (taller, contains label)
		graphics.fillStyle(accentColor, 1)
		graphics.fillRoundedRect(x, y, width, accentHeight, {
			tl: UI.statCard.borderRadius,
			tr: UI.statCard.borderRadius,
			bl: 0,
			br: 0,
		})

		// Subtle border
		graphics.lineStyle(1, accentColor, 0.3)
		graphics.strokeRoundedRect(x, y, width, height, UI.statCard.borderRadius)

		// Label text inside accent bar (dark text for contrast)
		const labelText = this.add.text(
			x + width / 2,
			y + accentHeight / 2,
			label,
			{
				fontFamily: gameFont,
				fontSize: '11px',
				color: '#1a1a2e',
				align: 'center',
			}
		)
		labelText.setOrigin(0.5, 0.5)
		labelText.setResolution(textResolution)
	}

	private updateTargetDisplay() {
		this.targetText.setText(`${this.gameState.targetScore}`)
	}

	private updateMovesDisplay() {
		this.movesText.setText(`${this.gameState.moves}`)
	}

	private updateProgressBar() {
		this.progressBar.clear()

		const barRadius = UI.progressBar.borderRadius

		// Background with subtle border
		this.progressBar.fillStyle(0x0a0a15, 1)
		this.progressBar.fillRoundedRect(
			UI.progressBar.x,
			UI.progressBar.y,
			UI.progressBar.width,
			UI.progressBar.height,
			barRadius
		)

		// Progress fill
		const progress = Math.min(
			this.gameState.score / this.gameState.targetScore,
			1
		)
		if (progress > 0) {
			const fillWidth = Math.max(UI.progressBar.width * progress, barRadius * 2)
			const fillColor = progress >= 1 ? 0x4caf50 : this.hudColors.target
			this.progressBar.fillStyle(fillColor, 1)
			this.progressBar.fillRoundedRect(
				UI.progressBar.x,
				UI.progressBar.y,
				fillWidth,
				UI.progressBar.height,
				barRadius
			)

			// Shine effect on progress
			this.progressBar.fillStyle(0xffffff, 0.2)
			this.progressBar.fillRoundedRect(
				UI.progressBar.x,
				UI.progressBar.y,
				fillWidth,
				UI.progressBar.height / 2,
				{ tl: barRadius, tr: barRadius, bl: 0, br: 0 }
			)
		}

		// Outer border
		this.progressBar.lineStyle(1, COLORS.headerBorder, 0.5)
		this.progressBar.strokeRoundedRect(
			UI.progressBar.x,
			UI.progressBar.y,
			UI.progressBar.width,
			UI.progressBar.height,
			barRadius
		)
	}

	// ==================== GRID CREATION ====================

	private createGrid() {
		this.gridContainer = this.add.container(GRID.offsetX, GRID.offsetY)
		this.grid = []

		for (let row = 0; row < GRID.size; row++) {
			this.grid[row] = []
			for (let col = 0; col < GRID.size; col++) {
				this.grid[row][col] = null
			}
		}
	}

	private fillGridWithCandies() {
		for (let row = 0; row < GRID.size; row++) {
			for (let col = 0; col < GRID.size; col++) {
				const candy = this.createCandy(row, col)
				this.grid[row][col] = candy
			}
		}
	}

	private createCandy(
		row: number,
		col: number,
		type?: number,
		bombType?: BombType
	): CandyData {
		// Determine if this should be a bomb (random spawn during fill)
		const bombConfig = this.levelConfig.bombConfig
		let isBomb = false
		let actualBombType: BombType | undefined = bombType

		// If bomb type is explicitly provided, use it
		if (actualBombType) {
			isBomb = true
		} else if (
			bombConfig &&
			type === undefined &&
			Math.random() < bombConfig.spawnChance
		) {
			// Random bomb spawn when filling empty cells
			isBomb = true
			actualBombType = Math.random() < 0.5 ? 'cross' : 'radius'
		}

		// Determine candy type
		let candyType: number
		if (isBomb && actualBombType) {
			// Bombs use their special frame and type -1 (so they don't match with each other)
			candyType = -1
		} else {
			candyType =
				type !== undefined ? type : Phaser.Math.Between(0, this.candyTypes - 1)
		}

		const x = col * (GRID.cellSize + GRID.gap) + GRID.cellSize / 2
		const y = row * (GRID.cellSize + GRID.gap) + GRID.cellSize / 2

		let sprite: Phaser.GameObjects.Sprite

		if (isBomb && actualBombType) {
			// Bombs always use spritesheet frames 7 or 8
			const frame = BOMB_FRAMES[actualBombType]
			sprite = this.add.sprite(x, y, 'candies', frame)
		} else if (this.useProcedural) {
			sprite = this.add.sprite(x, y, `candy-${candyType}`)
		} else {
			sprite = this.add.sprite(x, y, 'candies', candyType)
		}

		sprite.setDisplaySize(CANDY_SPRITE.displaySize, CANDY_SPRITE.displaySize)
		sprite.setInteractive()
		this.gridContainer.add(sprite)

		const candy: CandyData = {
			row,
			col,
			type: candyType,
			sprite,
			isBomb,
			bombType: actualBombType,
		}

		return candy
	}

	private removeInitialMatches() {
		let iterations = 0
		const maxIterations = 100

		while (iterations < maxIterations) {
			const matches = this.findAllMatches()
			if (matches.length === 0) break

			// Replace matched candies with different types
			for (const match of matches) {
				for (const cell of match.cells) {
					const candy = this.grid[cell.row][cell.col]
					if (candy && !candy.isBomb) {
						// Don't replace bombs - find a type that won't create a match
						const newType = this.findNonMatchingType(cell.row, cell.col)
						candy.type = newType

						// Update sprite
						if (candy.sprite) {
							if (this.useProcedural) {
								candy.sprite.setTexture(`candy-${newType}`)
							} else {
								candy.sprite.setFrame(newType)
							}
						}
					}
				}
			}

			iterations++
		}
	}

	private findNonMatchingType(row: number, col: number): number {
		const invalidTypes = new Set<number>()

		// Check horizontal neighbors
		if (col >= 2) {
			const left1 = this.grid[row][col - 1]
			const left2 = this.grid[row][col - 2]
			if (left1 && left2 && left1.type === left2.type) {
				invalidTypes.add(left1.type)
			}
		}

		// Check vertical neighbors
		if (row >= 2) {
			const up1 = this.grid[row - 1][col]
			const up2 = this.grid[row - 2][col]
			if (up1 && up2 && up1.type === up2.type) {
				invalidTypes.add(up1.type)
			}
		}

		// Find valid type
		const validTypes = []
		for (let t = 0; t < this.candyTypes; t++) {
			if (!invalidTypes.has(t)) {
				validTypes.push(t)
			}
		}

		return validTypes.length > 0
			? validTypes[Phaser.Math.Between(0, validTypes.length - 1)]
			: Phaser.Math.Between(0, this.candyTypes - 1)
	}

	// ==================== INPUT HANDLING ====================

	private setupInput() {
		let dragStartCandy: CandyData | null = null

		this.input.on('pointerdown', (pointer: Phaser.Input.Pointer) => {
			if (this.isAnimating || this.gameState.phase !== 'playing') return

			const cell = this.getCellFromPointer(pointer)
			if (cell) {
				const candy = this.grid[cell.row][cell.col]
				if (candy) {
					// Clear previous selection before selecting new candy
					if (this.selectedCandy && this.selectedCandy !== candy) {
						this.clearSelection()
					}
					dragStartCandy = candy
					this.selectCandy(candy)
				}
			}
		})

		this.input.on('pointermove', (pointer: Phaser.Input.Pointer) => {
			if (!pointer.isDown || this.isAnimating || !dragStartCandy) return
			if (this.gameState.phase !== 'playing') return

			const cell = this.getCellFromPointer(pointer)
			if (cell) {
				const targetCandy = this.grid[cell.row][cell.col]
				if (targetCandy && targetCandy !== dragStartCandy) {
					if (this.isAdjacent(dragStartCandy, targetCandy)) {
						this.clearSelection()
						this.trySwap(dragStartCandy, targetCandy)
						dragStartCandy = null
					}
				}
			}
		})

		this.input.on('pointerup', () => {
			// Clear selection when releasing without a valid swap
			if (dragStartCandy) {
				this.clearSelection()
			}
			dragStartCandy = null
		})
	}

	private getCellFromPointer(
		pointer: Phaser.Input.Pointer
	): { row: number; col: number } | null {
		const x = pointer.x - GRID.offsetX
		const y = pointer.y - GRID.offsetY

		const col = Math.floor(x / (GRID.cellSize + GRID.gap))
		const row = Math.floor(y / (GRID.cellSize + GRID.gap))

		if (row >= 0 && row < GRID.size && col >= 0 && col < GRID.size) {
			return { row, col }
		}
		return null
	}

	private isAdjacent(candy1: CandyData, candy2: CandyData): boolean {
		const dr = Math.abs(candy1.row - candy2.row)
		const dc = Math.abs(candy1.col - candy2.col)
		return (dr === 1 && dc === 0) || (dr === 0 && dc === 1)
	}

	private selectCandy(candy: CandyData) {
		this.selectedCandy = candy

		// Play select sound
		this.audio?.playSelect()

		// Draw selection indicator
		this.selectionIndicator.clear()
		this.selectionIndicator.lineStyle(3, 0xffffff, 1)

		const x = GRID.offsetX + candy.col * (GRID.cellSize + GRID.gap)
		const y = GRID.offsetY + candy.row * (GRID.cellSize + GRID.gap)

		this.selectionIndicator.strokeRoundedRect(
			x,
			y,
			GRID.cellSize,
			GRID.cellSize,
			8
		)

		// Scale up selected candy (relative to base scale)
		if (candy.sprite) {
			this.tweens.add({
				targets: candy.sprite,
				scale: CANDY_SPRITE.baseScale * ANIMATION.selectScale,
				duration: ANIMATION.selectDuration,
				ease: 'Back.easeOut',
			})
		}
	}

	private clearSelection() {
		if (this.selectedCandy?.sprite) {
			this.tweens.add({
				targets: this.selectedCandy.sprite,
				scale: CANDY_SPRITE.baseScale,
				duration: ANIMATION.selectDuration,
				ease: 'Back.easeIn',
			})
		}
		this.selectedCandy = null
		this.selectionIndicator.clear()
	}

	// ==================== SWAP LOGIC ====================

	private async trySwap(candy1: CandyData, candy2: CandyData) {
		this.isAnimating = true
		this.gameState.phase = 'animating'

		// Animate swap
		await this.animateSwap(candy1, candy2)

		// Swap in grid
		this.swapInGrid(candy1, candy2)

		// Check for matches at both positions
		const matches = this.findMatchesAtPositions([
			{ row: candy1.row, col: candy1.col },
			{ row: candy2.row, col: candy2.col },
		])

		if (matches.length > 0) {
			// Valid move - process matches
			this.decrementMoves()
			await this.processMatches(matches)
			this.checkGameEnd()
		} else {
			// Invalid move - swap back
			this.audio?.playInvalidMove()
			await this.animateSwap(candy1, candy2)
			this.swapInGrid(candy1, candy2)
		}

		this.isAnimating = false
		if (this.gameState.phase === 'animating') {
			this.gameState.phase = 'playing'
		}
	}

	private swapInGrid(candy1: CandyData, candy2: CandyData) {
		// Swap positions in grid array
		this.grid[candy1.row][candy1.col] = candy2
		this.grid[candy2.row][candy2.col] = candy1

		// Swap row/col properties
		const tempRow = candy1.row
		const tempCol = candy1.col
		candy1.row = candy2.row
		candy1.col = candy2.col
		candy2.row = tempRow
		candy2.col = tempCol
	}

	private async animateSwap(
		candy1: CandyData,
		candy2: CandyData
	): Promise<void> {
		// Play swap sound
		this.audio?.playSwap()

		return new Promise(resolve => {
			const x1 = candy1.col * (GRID.cellSize + GRID.gap) + GRID.cellSize / 2
			const y1 = candy1.row * (GRID.cellSize + GRID.gap) + GRID.cellSize / 2
			const x2 = candy2.col * (GRID.cellSize + GRID.gap) + GRID.cellSize / 2
			const y2 = candy2.row * (GRID.cellSize + GRID.gap) + GRID.cellSize / 2

			let completed = 0
			const checkComplete = () => {
				completed++
				if (completed === 2) resolve()
			}

			if (candy1.sprite) {
				this.tweens.add({
					targets: candy1.sprite,
					x: x2,
					y: y2,
					duration: ANIMATION.swapDuration,
					ease: 'Quad.easeOut',
					onComplete: checkComplete,
				})
			} else {
				checkComplete()
			}

			if (candy2.sprite) {
				this.tweens.add({
					targets: candy2.sprite,
					x: x1,
					y: y1,
					duration: ANIMATION.swapDuration,
					ease: 'Quad.easeOut',
					onComplete: checkComplete,
				})
			} else {
				checkComplete()
			}
		})
	}

	// ==================== MATCH DETECTION ====================

	private findAllMatches(): Match[] {
		const matches: Match[] = []

		// Find horizontal matches
		for (let row = 0; row < GRID.size; row++) {
			let matchStart = 0
			let matchLength = 1

			for (let col = 1; col <= GRID.size; col++) {
				const current = col < GRID.size ? this.grid[row][col] : null
				const previous = this.grid[row][col - 1]

				if (current && previous && current.type === previous.type) {
					matchLength++
				} else {
					if (matchLength >= 3 && previous) {
						const cells = []
						for (let c = matchStart; c < matchStart + matchLength; c++) {
							cells.push({ row, col: c })
						}
						matches.push({
							cells,
							type: 'horizontal',
							length: matchLength,
						})
					}
					matchStart = col
					matchLength = 1
				}
			}
		}

		// Find vertical matches
		for (let col = 0; col < GRID.size; col++) {
			let matchStart = 0
			let matchLength = 1

			for (let row = 1; row <= GRID.size; row++) {
				const current = row < GRID.size ? this.grid[row][col] : null
				const previous = this.grid[row - 1][col]

				if (current && previous && current.type === previous.type) {
					matchLength++
				} else {
					if (matchLength >= 3 && previous) {
						const cells = []
						for (let r = matchStart; r < matchStart + matchLength; r++) {
							cells.push({ row: r, col })
						}
						matches.push({
							cells,
							type: 'vertical',
							length: matchLength,
						})
					}
					matchStart = row
					matchLength = 1
				}
			}
		}

		return this.mergeIntersectingMatches(matches)
	}

	private findMatchesAtPositions(
		positions: { row: number; col: number }[]
	): Match[] {
		const allMatches: Match[] = []

		for (const pos of positions) {
			const candy = this.grid[pos.row][pos.col]
			if (!candy) continue

			// Bombs (type -1) can join any match when swapped
			// Check for adjacent matches if this is a bomb
			if (candy.isBomb) {
				// Check horizontal neighbors for any match
				const hMatch = this.findBombHorizontalMatch(pos.row, pos.col)
				if (hMatch.length >= 3) {
					const cells = hMatch.map(c => ({ row: pos.row, col: c }))
					allMatches.push({
						cells,
						type: 'horizontal',
						length: hMatch.length,
					})
				}

				// Check vertical neighbors for any match
				const vMatch = this.findBombVerticalMatch(pos.row, pos.col)
				if (vMatch.length >= 3) {
					const cells = vMatch.map(r => ({ row: r, col: pos.col }))
					allMatches.push({
						cells,
						type: 'vertical',
						length: vMatch.length,
					})
				}
			} else {
				// Regular candy matching
				// Check horizontal
				const hMatch = this.findHorizontalMatch(pos.row, pos.col, candy.type)
				if (hMatch.length >= 3) {
					const cells = hMatch.map(c => ({ row: pos.row, col: c }))
					allMatches.push({
						cells,
						type: 'horizontal',
						length: hMatch.length,
					})
				}

				// Check vertical
				const vMatch = this.findVerticalMatch(pos.row, pos.col, candy.type)
				if (vMatch.length >= 3) {
					const cells = vMatch.map(r => ({ row: r, col: pos.col }))
					allMatches.push({
						cells,
						type: 'vertical',
						length: vMatch.length,
					})
				}
			}
		}

		return this.mergeIntersectingMatches(allMatches)
	}

	// Find horizontal match for a bomb - looks at neighbors to find what type to match
	private findBombHorizontalMatch(row: number, col: number): number[] {
		// Look for adjacent candy type to adopt
		let targetType = -2 // Invalid
		if (
			col > 0 &&
			this.grid[row][col - 1] &&
			!this.grid[row][col - 1]!.isBomb
		) {
			targetType = this.grid[row][col - 1]!.type
		} else if (
			col < GRID.size - 1 &&
			this.grid[row][col + 1] &&
			!this.grid[row][col + 1]!.isBomb
		) {
			targetType = this.grid[row][col + 1]!.type
		}

		if (targetType < 0) return [col] // No valid neighbor

		const result = [col]

		// Extend left
		let c = col - 1
		while (c >= 0) {
			const neighbor = this.grid[row][c]
			if (neighbor && (neighbor.type === targetType || neighbor.isBomb)) {
				result.unshift(c)
				c--
			} else {
				break
			}
		}

		// Extend right
		c = col + 1
		while (c < GRID.size) {
			const neighbor = this.grid[row][c]
			if (neighbor && (neighbor.type === targetType || neighbor.isBomb)) {
				result.push(c)
				c++
			} else {
				break
			}
		}

		return result
	}

	// Find vertical match for a bomb - looks at neighbors to find what type to match
	private findBombVerticalMatch(row: number, col: number): number[] {
		// Look for adjacent candy type to adopt
		let targetType = -2 // Invalid
		if (
			row > 0 &&
			this.grid[row - 1][col] &&
			!this.grid[row - 1][col]!.isBomb
		) {
			targetType = this.grid[row - 1][col]!.type
		} else if (
			row < GRID.size - 1 &&
			this.grid[row + 1][col] &&
			!this.grid[row + 1][col]!.isBomb
		) {
			targetType = this.grid[row + 1][col]!.type
		}

		if (targetType < 0) return [row] // No valid neighbor

		const result = [row]

		// Extend up
		let r = row - 1
		while (r >= 0) {
			const neighbor = this.grid[r][col]
			if (neighbor && (neighbor.type === targetType || neighbor.isBomb)) {
				result.unshift(r)
				r--
			} else {
				break
			}
		}

		// Extend down
		r = row + 1
		while (r < GRID.size) {
			const neighbor = this.grid[r][col]
			if (neighbor && (neighbor.type === targetType || neighbor.isBomb)) {
				result.push(r)
				r++
			} else {
				break
			}
		}

		return result
	}

	private findHorizontalMatch(
		row: number,
		col: number,
		type: number
	): number[] {
		const result = [col]

		// Extend left
		let c = col - 1
		while (c >= 0 && this.grid[row][c]?.type === type) {
			result.unshift(c)
			c--
		}

		// Extend right
		c = col + 1
		while (c < GRID.size && this.grid[row][c]?.type === type) {
			result.push(c)
			c++
		}

		return result
	}

	private findVerticalMatch(row: number, col: number, type: number): number[] {
		const result = [row]

		// Extend up
		let r = row - 1
		while (r >= 0 && this.grid[r][col]?.type === type) {
			result.unshift(r)
			r--
		}

		// Extend down
		r = row + 1
		while (r < GRID.size && this.grid[r][col]?.type === type) {
			result.push(r)
			r++
		}

		return result
	}

	private mergeIntersectingMatches(matches: Match[]): Match[] {
		if (matches.length <= 1) return matches

		const result: Match[] = []
		const usedIndices = new Set<number>()

		// Find intersecting horizontal and vertical matches to create L/T shapes
		for (let i = 0; i < matches.length; i++) {
			if (usedIndices.has(i)) continue

			const match1 = matches[i]
			let merged = false

			for (let j = i + 1; j < matches.length; j++) {
				if (usedIndices.has(j)) continue

				const match2 = matches[j]

				// Check if one is horizontal and other is vertical
				if (
					(match1.type === 'horizontal' && match2.type === 'vertical') ||
					(match1.type === 'vertical' && match2.type === 'horizontal')
				) {
					// Find intersection point
					const intersection = this.findIntersection(match1, match2)
					if (intersection) {
						// Merge into L or T shape
						const mergedCells = new Map<string, { row: number; col: number }>()
						for (const cell of match1.cells) {
							mergedCells.set(`${cell.row},${cell.col}`, cell)
						}
						for (const cell of match2.cells) {
							mergedCells.set(`${cell.row},${cell.col}`, cell)
						}

						const cells = Array.from(mergedCells.values())
						const isT =
							match1.length >= 3 &&
							match2.length >= 3 &&
							(match1.length > 3 || match2.length > 3)

						result.push({
							cells,
							type: isT ? 't-shape' : 'l-shape',
							length: cells.length,
						})

						usedIndices.add(i)
						usedIndices.add(j)
						merged = true
						break
					}
				}
			}

			if (!merged) {
				result.push(match1)
				usedIndices.add(i)
			}
		}

		return result
	}

	private findIntersection(
		match1: Match,
		match2: Match
	): { row: number; col: number } | null {
		for (const cell1 of match1.cells) {
			for (const cell2 of match2.cells) {
				if (cell1.row === cell2.row && cell1.col === cell2.col) {
					return cell1
				}
			}
		}
		return null
	}

	private matchesOverlap(match1: Match, match2: Match): boolean {
		for (const cell1 of match1.cells) {
			for (const cell2 of match2.cells) {
				if (cell1.row === cell2.row && cell1.col === cell2.col) {
					return true
				}
			}
		}
		return false
	}

	// ==================== BOMB ACTIVATION ====================

	// Get all cells cleared by a cross bomb (entire row + column)
	private getCrossBombCells(bomb: CandyData): { row: number; col: number }[] {
		const cells: { row: number; col: number }[] = []
		const addedCells = new Set<string>()

		// Add entire row
		for (let c = 0; c < GRID.size; c++) {
			const key = `${bomb.row},${c}`
			if (!addedCells.has(key)) {
				cells.push({ row: bomb.row, col: c })
				addedCells.add(key)
			}
		}

		// Add entire column
		for (let r = 0; r < GRID.size; r++) {
			const key = `${r},${bomb.col}`
			if (!addedCells.has(key)) {
				cells.push({ row: r, col: bomb.col })
				addedCells.add(key)
			}
		}

		return cells
	}

	// Get all cells cleared by a radius bomb (3x3 area)
	private getRadiusBombCells(bomb: CandyData): { row: number; col: number }[] {
		const cells: { row: number; col: number }[] = []

		for (let dr = -1; dr <= 1; dr++) {
			for (let dc = -1; dc <= 1; dc++) {
				const r = bomb.row + dr
				const c = bomb.col + dc

				// Check bounds
				if (r >= 0 && r < GRID.size && c >= 0 && c < GRID.size) {
					cells.push({ row: r, col: c })
				}
			}
		}

		return cells
	}

	// Show bomb explosion visual effect
	private showBombExplosion(bomb: CandyData) {
		// Play bomb explosion sound
		this.audio?.playBombExplode(bomb.bombType)

		if (!bomb.sprite) return

		const x = bomb.sprite.x + GRID.offsetX
		const y = bomb.sprite.y + GRID.offsetY

		// Create explosion ring
		const explosion = this.add.graphics()
		explosion.setPosition(x, y)

		// Inner flash
		explosion.fillStyle(0xffffff, 0.8)
		explosion.fillCircle(0, 0, 20)

		// Animate expansion and fade
		this.tweens.add({
			targets: explosion,
			scale: bomb.bombType === 'cross' ? 4 : 2.5,
			alpha: 0,
			duration: 400,
			ease: 'Quad.easeOut',
			onComplete: () => explosion.destroy(),
		})

		// Create extra particles for bombs
		const particleCount = bomb.bombType === 'cross' ? 16 : 12
		for (let i = 0; i < particleCount; i++) {
			const angle = (i / particleCount) * Math.PI * 2
			const distance = bomb.bombType === 'cross' ? 80 : 50

			const particle = this.add.graphics()
			particle.fillStyle(0xffd700, 1)
			particle.fillCircle(0, 0, 6)
			particle.setPosition(x, y)

			this.tweens.add({
				targets: particle,
				x: x + Math.cos(angle) * distance,
				y: y + Math.sin(angle) * distance,
				alpha: 0,
				scale: 0,
				duration: 500,
				ease: 'Quad.easeOut',
				onComplete: () => particle.destroy(),
			})
		}
	}

	// Calculate bomb activation score
	private calculateBombScore(bomb: CandyData, cellsCleared: number): number {
		const baseScore =
			bomb.bombType === 'cross'
				? BOMB_SCORING.crossActivation
				: BOMB_SCORING.radiusActivation
		return baseScore + cellsCleared * BOMB_SCORING.perCandyCleared
	}

	// ==================== MATCH PROCESSING ====================

	private async processMatches(matches: Match[]) {
		let chainLevel = 1

		while (matches.length > 0) {
			// Show chain indicator
			if (chainLevel > 1) {
				this.showChainIndicator(chainLevel)
			}

			// Find bombs in the matches
			const bombsInMatches: CandyData[] = []
			for (const match of matches) {
				for (const cell of match.cells) {
					const candy = this.grid[cell.row][cell.col]
					if (candy?.isBomb) {
						bombsInMatches.push(candy)
					}
				}
			}

			// Collect all cells to clear (from matches + bomb activations)
			const cellsToClear = new Map<string, { row: number; col: number }>()

			// Add match cells
			for (const match of matches) {
				for (const cell of match.cells) {
					cellsToClear.set(`${cell.row},${cell.col}`, cell)
				}
			}

			// Process bomb activations and chain reactions
			const processedBombs = new Set<string>()
			const bombQueue = [...bombsInMatches]
			let totalBombScore = 0

			while (bombQueue.length > 0) {
				const bomb = bombQueue.shift()!
				const bombKey = `${bomb.row},${bomb.col}`

				if (processedBombs.has(bombKey)) continue
				processedBombs.add(bombKey)

				// Show explosion effect
				this.showBombExplosion(bomb)

				// Get cells cleared by this bomb
				const bombCells =
					bomb.bombType === 'cross'
						? this.getCrossBombCells(bomb)
						: this.getRadiusBombCells(bomb)

				// Check for chain reactions (bombs cleared by other bombs)
				for (const cell of bombCells) {
					const key = `${cell.row},${cell.col}`
					if (!cellsToClear.has(key)) {
						cellsToClear.set(key, cell)

						// Check if this cell contains a bomb (chain reaction)
						const clearedCandy = this.grid[cell.row][cell.col]
						if (
							clearedCandy?.isBomb &&
							!processedBombs.has(`${clearedCandy.row},${clearedCandy.col}`)
						) {
							bombQueue.push(clearedCandy)
						}
					}
				}

				// Calculate bomb score
				totalBombScore += this.calculateBombScore(bomb, bombCells.length)
			}

			// Calculate points (regular matches + bomb bonus)
			const matchPoints = this.calculateMatchPoints(matches, chainLevel)
			this.addScore(matchPoints + totalBombScore)

			// Play match sound based on the largest match length
			const maxMatchLength = Math.max(...matches.map(m => m.length))
			this.audio?.playMatchSound(maxMatchLength)

			// Create matches array from cells to clear for animation
			const cellsArray = Array.from(cellsToClear.values())
			const clearMatch: Match = {
				cells: cellsArray,
				type: 'horizontal', // Type doesn't matter for clearing
				length: cellsArray.length,
			}

			// Check for 4+ matches to potentially spawn bombs as rewards
			const bombReward = this.checkForBombReward(matches)

			// Animate and remove all cells
			await this.animateMatches([clearMatch])
			this.removeMatches([clearMatch])

			// Drop candies
			await this.dropCandies()

			// Fill empty cells (potentially with bomb reward)
			await this.fillEmptyCells(bombReward)

			// Check for new matches (cascade)
			matches = this.findAllMatches()
			chainLevel++
		}

		this.gameState.chainLevel = chainLevel - 1

		// Check if board needs shuffling (no valid moves available)
		await this.checkAndShuffleIfNeeded()
	}

	// Check if matches should reward a bomb
	private checkForBombReward(
		matches: Match[]
	): { row: number; col: number; bombType: BombType } | null {
		const bombConfig = this.levelConfig.bombConfig
		if (!bombConfig) return null

		// Check for 4+ length matches
		for (const match of matches) {
			if (match.length >= 4 && Math.random() < bombConfig.matchSpawnChance) {
				// 5+ match gets cross bomb, 4 match gets radius bomb
				const bombType: BombType = match.length >= 5 ? 'cross' : 'radius'
				// Spawn at the center of the match
				const centerIndex = Math.floor(match.cells.length / 2)
				const cell = match.cells[centerIndex]
				return { row: cell.row, col: cell.col, bombType }
			}
		}

		return null
	}

	private calculateMatchPoints(matches: Match[], chainLevel: number): number {
		let points = 0

		for (const match of matches) {
			if (match.length === 3) {
				points += SCORING.match3
			} else if (match.length === 4) {
				points += SCORING.match4
			} else if (match.length >= 5) {
				points += SCORING.match5
			}

			// L/T shape bonus
			if (match.type === 'l-shape' || match.type === 't-shape') {
				points += SCORING.matchLT - SCORING.match3
			}
		}

		// Chain bonus
		if (chainLevel > 1) {
			points += SCORING.chainBonus * (chainLevel - 1)
		}

		return points
	}

	private async animateMatches(matches: Match[]): Promise<void> {
		const animations: Promise<void>[] = []

		const processedCells = new Set<string>()

		for (const match of matches) {
			for (const cell of match.cells) {
				const key = `${cell.row},${cell.col}`
				if (processedCells.has(key)) continue
				processedCells.add(key)

				const candy = this.grid[cell.row][cell.col]
				if (candy) {
					animations.push(this.animateClearCandy(candy))
				}
			}
		}

		await Promise.all(animations)
	}

	private async animateClearCandy(candy: CandyData): Promise<void> {
		return new Promise(resolve => {
			if (!candy.sprite) {
				resolve()
				return
			}

			// Create particles
			this.createMatchParticles(candy)

			// Scale down and fade sprite
			this.tweens.add({
				targets: candy.sprite,
				scale: 0,
				alpha: 0,
				duration: ANIMATION.clearDuration,
				ease: 'Back.easeIn',
				onComplete: () => resolve(),
			})
		})
	}

	private createMatchParticles(candy: CandyData) {
		if (!candy.sprite) return

		const color = CANDY_COLORS[candy.type]
		const useSprites = this.textures.exists('particles')

		// Create particles
		for (let i = 0; i < 6; i++) {
			const x = candy.sprite.x + GRID.offsetX
			const y = candy.sprite.y + GRID.offsetY
			const angle = (i / 6) * Math.PI * 2
			const distance = 30 + Math.random() * 20

			if (useSprites) {
				// Use particle spritesheet with random frame (0-8)
				const frame = Phaser.Math.Between(0, 8)
				const particle = this.add.sprite(x, y, 'particles', frame)
				particle.setTint(color)
				particle.setScale(0.4)

				this.tweens.add({
					targets: particle,
					x: x + Math.cos(angle) * distance,
					y: y + Math.sin(angle) * distance,
					alpha: 0,
					scale: 0,
					duration: 400,
					ease: 'Quad.easeOut',
					onComplete: () => particle.destroy(),
				})
			} else {
				// Fallback to graphics
				const particle = this.add.graphics()
				particle.fillStyle(color, 1)
				particle.fillCircle(0, 0, 4)
				particle.x = x
				particle.y = y

				this.tweens.add({
					targets: particle,
					x: x + Math.cos(angle) * distance,
					y: y + Math.sin(angle) * distance,
					alpha: 0,
					scale: 0,
					duration: 400,
					ease: 'Quad.easeOut',
					onComplete: () => particle.destroy(),
				})
			}
		}
	}

	private removeMatches(matches: Match[]) {
		const processedCells = new Set<string>()

		for (const match of matches) {
			for (const cell of match.cells) {
				const key = `${cell.row},${cell.col}`
				if (processedCells.has(key)) continue
				processedCells.add(key)

				const candy = this.grid[cell.row][cell.col]
				if (candy) {
					this.destroyCandy(candy)
					this.grid[cell.row][cell.col] = null
				}
			}
		}
	}

	private destroyCandy(candy: CandyData) {
		if (candy.sprite) {
			candy.sprite.destroy()
			candy.sprite = null
		}
	}

	// ==================== CASCADE ====================

	private async dropCandies(): Promise<void> {
		const animations: Promise<void>[] = []

		for (let col = 0; col < GRID.size; col++) {
			let emptyRow = GRID.size - 1

			for (let row = GRID.size - 1; row >= 0; row--) {
				const candy = this.grid[row][col]
				if (candy) {
					if (row !== emptyRow) {
						// Move candy down
						this.grid[emptyRow][col] = candy
						this.grid[row][col] = null
						candy.row = emptyRow

						const dropDistance = emptyRow - row
						animations.push(this.animateDrop(candy, dropDistance))
					}
					emptyRow--
				}
			}
		}

		await Promise.all(animations)
	}

	private async animateDrop(candy: CandyData, distance: number): Promise<void> {
		return new Promise(resolve => {
			if (!candy.sprite) {
				resolve()
				return
			}

			const targetY = candy.row * (GRID.cellSize + GRID.gap) + GRID.cellSize / 2

			this.tweens.add({
				targets: candy.sprite,
				y: targetY,
				duration: ANIMATION.dropDurationPerRow * distance,
				ease: 'Bounce.easeOut',
				onComplete: () => resolve(),
			})
		})
	}

	private async fillEmptyCells(
		bombReward?: { row: number; col: number; bombType: BombType } | null
	): Promise<void> {
		const animations: Promise<void>[] = []

		for (let col = 0; col < GRID.size; col++) {
			// Count empty cells in this column (from top)
			const emptyCells: number[] = []
			for (let row = 0; row < GRID.size; row++) {
				if (!this.grid[row][col]) {
					emptyCells.push(row)
				}
			}

			// Fill from bottom to top (so lower positions get filled first)
			for (let i = emptyCells.length - 1; i >= 0; i--) {
				const row = emptyCells[i]
				const fallIndex = emptyCells.length - i // 1 for bottom-most, increasing upward

				// Check if this is the bomb reward position
				let candy: CandyData
				if (bombReward && bombReward.row === row && bombReward.col === col) {
					candy = this.createCandy(row, col, undefined, bombReward.bombType)
				} else {
					candy = this.createCandy(row, col)
				}

				this.grid[row][col] = candy

				// Start above the grid - higher for candies filling higher rows
				if (candy.sprite) {
					const startY = -GRID.cellSize * fallIndex - GRID.cellSize / 2
					candy.sprite.y = startY

					animations.push(this.animateFill(candy, fallIndex))
				}
			}
		}

		await Promise.all(animations)
	}

	private async animateFill(candy: CandyData, delay: number): Promise<void> {
		return new Promise(resolve => {
			if (!candy.sprite) {
				resolve()
				return
			}

			const targetY = candy.row * (GRID.cellSize + GRID.gap) + GRID.cellSize / 2

			this.tweens.add({
				targets: candy.sprite,
				y: targetY,
				duration: ANIMATION.dropDurationPerRow * (candy.row + delay + 1),
				ease: 'Bounce.easeOut',
				delay: delay * 50,
				onComplete: () => resolve(),
			})
		})
	}

	// ==================== GAME STATE ====================

	private decrementMoves() {
		this.gameState.moves--
		this.updateMovesDisplay()
		this.onMovesUpdate(this.gameState.moves)
	}

	private addScore(points: number) {
		this.gameState.score += points
		this.scoreText.setText(this.gameState.score.toString())
		this.updateProgressBar()
		this.onScoreUpdate(this.gameState.score)

		// Show score popup
		this.showScorePopup(points)
	}

	private showScorePopup(points: number) {
		// Play score popup sound
		this.audio?.playScorePopup()

		const popup = this.add.text(GAME_WIDTH / 2, GAME_HEIGHT / 2, `+${points}`, {
			fontFamily: '"Luckiest Guy", Arial, sans-serif',
			fontSize: '36px',
			color: '#ffd700',
			stroke: '#000000',
			strokeThickness: 4,
		})
		popup.setOrigin(0.5, 0.5)
		popup.setDepth(100)
		popup.setResolution(Math.min(window.devicePixelRatio || 1, 2))

		this.tweens.add({
			targets: popup,
			y: popup.y - 50,
			alpha: 0,
			scale: 1.5,
			duration: ANIMATION.scorePopupDuration,
			ease: 'Quad.easeOut',
			onComplete: () => popup.destroy(),
		})
	}

	private showChainIndicator(chainLevel: number) {
		// Play combo sound
		this.audio?.playCombo(chainLevel)

		this.chainIndicator.setText(`¡Combo x${chainLevel}!`)
		this.chainIndicator.setAlpha(1)

		this.tweens.add({
			targets: this.chainIndicator,
			alpha: 0,
			duration: ANIMATION.chainIndicatorDuration,
			ease: 'Quad.easeIn',
		})
	}

	private checkGameEnd() {
		if (this.gameState.score >= this.gameState.targetScore) {
			// Win! Add bonus points for remaining moves
			const movesBonus = this.gameState.moves * SCORING.movesBonus
			if (movesBonus > 0) {
				this.addScore(movesBonus)
				this.showMovesBonus(movesBonus)
			}
			this.gameState.phase = 'result'
			this.onPhaseChange('result')
			this.audio?.playWin()
			this.onGameComplete(true, this.gameState.score)
		} else if (this.gameState.moves <= 0) {
			// Out of moves - fail
			this.gameState.phase = 'result'
			this.onPhaseChange('result')
			this.audio?.playLose()
			this.onGameComplete(false, this.gameState.score)
		}
	}

	private showMovesBonus(bonus: number) {
		const bonusText = this.add.text(
			GAME_WIDTH / 2,
			GAME_HEIGHT / 2 - 40,
			`¡Bonus por turnos!\n+${bonus}`,
			{
				fontFamily: '"Luckiest Guy", Arial, sans-serif',
				fontSize: '28px',
				color: '#4caf50',
				align: 'center',
				stroke: '#000000',
				strokeThickness: 4,
			}
		)
		bonusText.setOrigin(0.5, 0.5)
		bonusText.setDepth(100)
		bonusText.setResolution(Math.min(window.devicePixelRatio || 1, 2))

		this.tweens.add({
			targets: bonusText,
			y: bonusText.y - 60,
			alpha: 0,
			scale: 1.3,
			duration: 1500,
			ease: 'Quad.easeOut',
			onComplete: () => bonusText.destroy(),
		})
	}

	// ==================== SHUFFLE MECHANISM ====================

	private hasValidMoves(): boolean {
		// Check if any swap would create a match
		for (let row = 0; row < GRID.size; row++) {
			for (let col = 0; col < GRID.size; col++) {
				// Check swap right
				if (
					col < GRID.size - 1 &&
					this.wouldCreateMatch(row, col, row, col + 1)
				) {
					return true
				}
				// Check swap down
				if (
					row < GRID.size - 1 &&
					this.wouldCreateMatch(row, col, row + 1, col)
				) {
					return true
				}
			}
		}
		return false
	}

	private wouldCreateMatch(
		row1: number,
		col1: number,
		row2: number,
		col2: number
	): boolean {
		const candy1 = this.grid[row1][col1]
		const candy2 = this.grid[row2][col2]
		if (!candy1 || !candy2) return false

		// Temporarily swap
		this.grid[row1][col1] = candy2
		this.grid[row2][col2] = candy1
		const tempRow = candy1.row
		const tempCol = candy1.col
		candy1.row = row2
		candy1.col = col2
		candy2.row = row1
		candy2.col = col1

		let hasMatch = false

		// Check for matches at both positions
		// Handle bombs specially - they can join any match
		if (candy2.isBomb) {
			hasMatch =
				hasMatch ||
				this.findBombHorizontalMatch(row1, col1).length >= 3 ||
				this.findBombVerticalMatch(row1, col1).length >= 3
		} else {
			hasMatch =
				hasMatch ||
				this.findHorizontalMatch(row1, col1, candy2.type).length >= 3 ||
				this.findVerticalMatch(row1, col1, candy2.type).length >= 3
		}

		if (candy1.isBomb) {
			hasMatch =
				hasMatch ||
				this.findBombHorizontalMatch(row2, col2).length >= 3 ||
				this.findBombVerticalMatch(row2, col2).length >= 3
		} else {
			hasMatch =
				hasMatch ||
				this.findHorizontalMatch(row2, col2, candy1.type).length >= 3 ||
				this.findVerticalMatch(row2, col2, candy1.type).length >= 3
		}

		// Swap back
		this.grid[row1][col1] = candy1
		this.grid[row2][col2] = candy2
		candy1.row = tempRow
		candy1.col = tempCol
		candy2.row = row2
		candy2.col = col2

		return hasMatch
	}

	private async shuffleBoard(): Promise<void> {
		// Show shuffle message
		const shuffleText = this.add.text(
			GAME_WIDTH / 2,
			GAME_HEIGHT / 2,
			'Sin movimientos\n¡Mezclando!',
			{
				fontFamily: '"Luckiest Guy", Arial, sans-serif',
				fontSize: '28px',
				color: '#ffffff',
				align: 'center',
				stroke: '#000000',
				strokeThickness: 4,
			}
		)
		shuffleText.setOrigin(0.5, 0.5)
		shuffleText.setDepth(100)
		shuffleText.setResolution(Math.min(window.devicePixelRatio || 1, 2))

		// Fade in
		shuffleText.setAlpha(0)
		await new Promise<void>(resolve => {
			this.tweens.add({
				targets: shuffleText,
				alpha: 1,
				duration: 300,
				onComplete: () => resolve(),
			})
		})

		// Collect candy types and bombs (bombs stay in place)
		const candyTypes: number[] = []
		const bombs: { row: number; col: number; bombType: BombType }[] = []

		for (let row = 0; row < GRID.size; row++) {
			for (let col = 0; col < GRID.size; col++) {
				const candy = this.grid[row][col]
				if (candy) {
					if (candy.isBomb && candy.bombType) {
						bombs.push({ row, col, bombType: candy.bombType })
					} else {
						candyTypes.push(candy.type)
					}
				}
			}
		}

		// Fisher-Yates shuffle for regular candies only
		for (let i = candyTypes.length - 1; i > 0; i--) {
			const j = Phaser.Math.Between(0, i)
			;[candyTypes[i], candyTypes[j]] = [candyTypes[j], candyTypes[i]]
		}

		// Destroy all existing candies
		for (let row = 0; row < GRID.size; row++) {
			for (let col = 0; col < GRID.size; col++) {
				const candy = this.grid[row][col]
				if (candy) {
					this.destroyCandy(candy)
					this.grid[row][col] = null
				}
			}
		}

		// Create a set of bomb positions for quick lookup
		const bombPositions = new Set(bombs.map(b => `${b.row},${b.col}`))

		// Redistribute candies and bombs
		let dataIndex = 0
		for (let row = 0; row < GRID.size; row++) {
			for (let col = 0; col < GRID.size; col++) {
				const key = `${row},${col}`
				if (bombPositions.has(key)) {
					// Restore bomb at its original position
					const bomb = bombs.find(b => b.row === row && b.col === col)!
					const candy = this.createCandy(row, col, undefined, bomb.bombType)
					this.grid[row][col] = candy
				} else {
					const candyType = candyTypes[dataIndex++]
					const candy = this.createCandy(row, col, candyType)
					this.grid[row][col] = candy
				}
			}
		}

		// Remove any matches created by shuffle
		this.removeInitialMatches()

		// Short delay for visual effect
		await new Promise<void>(resolve => {
			this.time.delayedCall(500, resolve)
		})

		// Fade out shuffle text
		await new Promise<void>(resolve => {
			this.tweens.add({
				targets: shuffleText,
				alpha: 0,
				duration: 300,
				onComplete: () => {
					shuffleText.destroy()
					resolve()
				},
			})
		})
	}

	private async checkAndShuffleIfNeeded(): Promise<void> {
		// Keep shuffling until we have valid moves (max 10 attempts to prevent infinite loop)
		let attempts = 0
		while (!this.hasValidMoves() && attempts < 10) {
			await this.shuffleBoard()
			attempts++
		}
	}
}
