import Phaser from 'phaser'
import { GAME_WIDTH, GAME_HEIGHT, CANDY_COLORS } from '../constants'

export class BootScene extends Phaser.Scene {
	constructor() {
		super({ key: 'BootScene' })
	}

	preload() {
		// Create loading bar
		const progressBar = this.add.graphics()
		const progressBox = this.add.graphics()

		progressBox.fillStyle(0x222222, 0.8)
		progressBox.fillRect(GAME_WIDTH / 2 - 160, GAME_HEIGHT / 2 - 25, 320, 50)

		const loadingText = this.add.text(
			GAME_WIDTH / 2,
			GAME_HEIGHT / 2 - 50,
			'Cargando...',
			{
				fontFamily: '"Luckiest Guy", Arial, sans-serif',
				fontSize: '24px',
				color: '#ffffff',
			}
		)
		loadingText.setOrigin(0.5, 0.5)
		loadingText.setResolution(Math.min(window.devicePixelRatio || 1, 2))

		// Progress bar update
		this.load.on('progress', (value: number) => {
			progressBar.clear()
			progressBar.fillStyle(CANDY_COLORS[3], 1) // Green
			progressBar.fillRect(
				GAME_WIDTH / 2 - 150,
				GAME_HEIGHT / 2 - 15,
				300 * value,
				30
			)
		})

		this.load.on('complete', () => {
			progressBar.destroy()
			progressBox.destroy()
			loadingText.destroy()
		})

		// Build image paths based on skin
		const skin = this.registry.get('skin') as string | undefined
		const basePath = '/games/candy-crush/sprites/'
		const skinPath = skin ? `skins/${skin}/` : ''

		// Try to load candy spritesheet
		// Falls back to procedural graphics if not available
		this.load.spritesheet('candies', `${basePath}${skinPath}candies.webp`, {
			frameWidth: 84,
			frameHeight: 84,
		})

		// Load particle spritesheet (9 frames, 128x128 each)
		this.load.spritesheet('particles', `${basePath}${skinPath}particles.webp`, {
			frameWidth: 128,
			frameHeight: 128,
		})
	}

	create() {
		// Check if candies loaded, if not we'll use procedural graphics
		const candiesLoaded = this.textures.exists('candies')
		this.registry.set('useProcedural', !candiesLoaded)

		// Generate procedural candy textures if needed
		if (!candiesLoaded) {
			this.generateProceduralCandies()
		}

		// Generate a simple particle texture if spritesheet not loaded
		if (!this.textures.exists('particles')) {
			this.generateParticleTexture()
		}

		// Transition to main game scene
		this.scene.start('MainScene')
	}

	private generateProceduralCandies() {
		// Generate candy textures using graphics
		const graphics = this.make.graphics({ x: 0, y: 0 })

		for (let i = 0; i < CANDY_COLORS.length; i++) {
			graphics.clear()

			// Draw candy circle with gradient-like effect
			const color = CANDY_COLORS[i]

			// Outer glow
			graphics.fillStyle(color, 0.3)
			graphics.fillCircle(32, 32, 30)

			// Main body
			graphics.fillStyle(color, 1)
			graphics.fillCircle(32, 32, 26)

			// Highlight
			graphics.fillStyle(0xffffff, 0.4)
			graphics.fillCircle(26, 26, 10)

			// Inner highlight
			graphics.fillStyle(0xffffff, 0.6)
			graphics.fillCircle(24, 24, 5)

			// Generate texture from graphics
			graphics.generateTexture(`candy-${i}`, 64, 64)
		}

		graphics.destroy()
	}

	private generateParticleTexture() {
		const graphics = this.make.graphics({ x: 0, y: 0 })

		// Simple circular particle
		graphics.fillStyle(0xffffff, 1)
		graphics.fillCircle(8, 8, 6)
		graphics.fillStyle(0xffffff, 0.5)
		graphics.fillCircle(8, 8, 8)

		graphics.generateTexture('particle', 16, 16)
		graphics.destroy()
	}
}
