import React, { useEffect, useRef, useCallback } from 'react'
import Phaser from 'phaser'
import { BootScene } from './scenes/BootScene'
import { MainScene } from './scenes/MainScene'
import { GAME_WIDTH, GAME_HEIGHT, COLORS } from './constants'
import { GamePhase, LevelConfig } from './types'
import { candyCrushAudio } from './utils/audioManager'
import { hapticManager } from '../utils/hapticManager'

interface CandyCrushCoreProps {
	onScoreUpdate: (score: number) => void
	onMovesUpdate: (moves: number) => void
	onGameComplete: (won: boolean, score: number) => void
	onPhaseChange?: (phase: GamePhase) => void
	brandColor?: string
	skin?: string
	lives?: number
	levelConfig: LevelConfig
}

const CandyCrushCore: React.FC<CandyCrushCoreProps> = ({
	onScoreUpdate,
	onMovesUpdate,
	onGameComplete,
	onPhaseChange,
	brandColor,
	skin,
	lives = 3,
	levelConfig,
}) => {
	const gameContainerRef = useRef<HTMLDivElement>(null)
	const gameRef = useRef<Phaser.Game | null>(null)

	// Track previous score for haptic feedback on matches
	const prevScoreRef = useRef(0)

	// Memoize callbacks to prevent unnecessary re-renders
	const handleScoreUpdate = useCallback(
		(score: number) => {
			onScoreUpdate(score)
			// Haptic feedback when score increases (match made)
			if (score > prevScoreRef.current) {
				const scoreDiff = score - prevScoreRef.current
				// Combo/cascade gives bigger haptic
				if (scoreDiff >= 100) {
					hapticManager.comboMilestone()
				} else {
					hapticManager.goodHit()
				}
			}
			prevScoreRef.current = score
		},
		[onScoreUpdate]
	)

	const handleMovesUpdate = useCallback(
		(moves: number) => {
			onMovesUpdate(moves)
		},
		[onMovesUpdate]
	)

	const handleGameComplete = useCallback(
		(won: boolean, score: number) => {
			onGameComplete(won, score)
			// Haptic feedback for game complete
			if (won) {
				hapticManager.levelUp()
			} else {
				hapticManager.miss()
			}
		},
		[onGameComplete]
	)

	const handlePhaseChange = useCallback(
		(phase: GamePhase) => {
			if (onPhaseChange) {
				onPhaseChange(phase)
			}
		},
		[onPhaseChange]
	)

	// Initialize Phaser game and haptics
	useEffect(() => {
		if (!gameContainerRef.current || gameRef.current) return

		hapticManager.init()

		// Use higher base resolution for crisp text on all displays
		const config: Phaser.Types.Core.GameConfig = {
			type: Phaser.WEBGL,
			parent: gameContainerRef.current,
			width: GAME_WIDTH,
			height: GAME_HEIGHT,
			backgroundColor: COLORS.background,
			scene: [BootScene, MainScene],
			scale: {
				mode: Phaser.Scale.FIT,
				autoCenter: Phaser.Scale.CENTER_BOTH,
			},
			render: {
				pixelArt: false,
				antialias: true,
				antialiasGL: true,
				batchSize: 4096,
			},
			input: {
				activePointers: 1,
			},
		}

		gameRef.current = new Phaser.Game(config)

		// Pass callbacks to Phaser via registry
		gameRef.current.registry.set('onScoreUpdate', handleScoreUpdate)
		gameRef.current.registry.set('onMovesUpdate', handleMovesUpdate)
		gameRef.current.registry.set('onGameComplete', handleGameComplete)
		gameRef.current.registry.set('onPhaseChange', handlePhaseChange)
		gameRef.current.registry.set('brandColor', brandColor)
		gameRef.current.registry.set('skin', skin)
		gameRef.current.registry.set('lives', lives)
		gameRef.current.registry.set('levelConfig', levelConfig)
		gameRef.current.registry.set('audioManager', candyCrushAudio)

		// Cleanup on unmount
		return () => {
			if (gameRef.current) {
				gameRef.current.destroy(true)
				gameRef.current = null
			}
		}
	}, [
		handleScoreUpdate,
		handleMovesUpdate,
		handleGameComplete,
		handlePhaseChange,
		brandColor,
		skin,
		lives,
		levelConfig,
	])

	return (
		<div
			ref={gameContainerRef}
			className="game-loading"
			style={{
				touchAction: 'none',
				userSelect: 'none',
			}}
		/>
	)
}

export default CandyCrushCore
